import{_ as t,c as a,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Get Started with AI App Factory: Install to Run Your First App | agent-app-factory","description":"Learn how to quickly start AI App Factory, from installing and configuring the CLI tool to understanding how the 7-stage pipeline works, and master initializing a project to begin your first app generation journey. This chapter covers four core lessons: Quick Start, Installation and Configuration, Project Initialization, and Pipeline Overview, helping you fully understand the end-to-end automation process from idea to runnable app.","frontmatter":{"title":"Get Started with AI App Factory: Install to Run Your First App | agent-app-factory","sidebarTitle":"Get Started","subtitle":"Get Started","description":"Learn how to quickly start AI App Factory, from installing and configuring the CLI tool to understanding how the 7-stage pipeline works, and master initializing a project to begin your first app generation journey. This chapter covers four core lessons: Quick Start, Installation and Configuration, Project Initialization, and Pipeline Overview, helping you fully understand the end-to-end automation process from idea to runnable app.","order":10},"headers":[],"relativePath":"hyz1992/agent-app-factory/start/index.md","filePath":"hyz1992/agent-app-factory/start/index.md"}'),o={name:"hyz1992/agent-app-factory/start/index.md"};function r(l,e,s,p,d,c){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="get-started" tabindex="-1">Get Started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get Started&quot;">​</a></h1><p>This chapter helps you quickly get started with AI App Factory, understand its core value, install and configure the tools, and grasp the working principle of the 7-stage pipeline, preparing you to generate your first application.</p><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to &quot;Learning Path&quot;">​</a></h2><p>We recommend following this order to learn the content in this chapter:</p><h3 id="_1-quick-start-from-idea-to-app" tabindex="-1">1. <a href="./../getting-started/">Quick Start: From Idea to App</a> <a class="header-anchor" href="#_1-quick-start-from-idea-to-app" aria-label="Permalink to &quot;1. [Quick Start: From Idea to App](../getting-started/)&quot;">​</a></h3><p>Understand AI App Factory&#39;s core value and prerequisites, and experience the end-to-end process from idea to app through a complete case.</p><ul><li>Understand the checkpoint-based multi-agent collaboration mechanism</li><li>Learn about the complete workflow of the 7-stage pipeline</li><li>Master the skill of providing clear product descriptions</li></ul><h3 id="_2-installation-and-configuration" tabindex="-1">2. <a href="./../installation/">Installation and Configuration</a> <a class="header-anchor" href="#_2-installation-and-configuration" aria-label="Permalink to &quot;2. [Installation and Configuration](../installation/)&quot;">​</a></h3><p>Globally install the CLI tool and configure the AI assistant (Claude Code/OpenCode) and related environment.</p><ul><li>Install agent-app-factory globally using npm</li><li>Configure Claude Code or OpenCode</li><li>Verify that installation was successful</li></ul><h3 id="_3-initialize-factory-project" tabindex="-1">3. <a href="./../init-project/">Initialize Factory Project</a> <a class="header-anchor" href="#_3-initialize-factory-project" aria-label="Permalink to &quot;3. [Initialize Factory Project](../init-project/)&quot;">​</a></h3><p>Use the <code>factory init</code> command to initialize the directory and understand the generated project structure and configuration files.</p><ul><li>Execute the project initialization command</li><li>Understand the project directory structure and configuration files</li><li>Prepare product idea input</li></ul><h3 id="_4-7-stage-pipeline-overview" tabindex="-1">4. <a href="./../pipeline-overview/">7-Stage Pipeline Overview</a> <a class="header-anchor" href="#_4-7-stage-pipeline-overview" aria-label="Permalink to &quot;4. [7-Stage Pipeline Overview](../pipeline-overview/)&quot;">​</a></h3><p>Deeply understand the complete pipeline process from Bootstrap to Preview, including the input/output of each stage and the checkpoint mechanism.</p><ul><li>Understand the goals and artifacts of the 7 stages</li><li>Master the checkpoint mechanism and manual confirmation process</li><li>Learn how to control pipeline execution</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before starting this chapter, you need:</p><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><ol><li><strong>Node.js Environment</strong>: Node.js v18 or higher installed</li><li><strong>AI Programming Assistant</strong>: Must configure one of the following tools <ul><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a> (Recommended) ⭐</li><li><a href="https://opencode.design/" target="_blank" rel="noreferrer">OpenCode</a> or other AI assistants that support Agent mode</li></ul></li><li><strong>Basic Command Line Skills</strong>: Ability to execute commands using terminal</li></ol></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you will master:</p><ul><li>✅ The core working principle of AI App Factory</li><li>✅ Installation and configuration of the CLI tool</li><li>✅ Project initialization and structure understanding</li><li>✅ The complete process of the 7-stage pipeline</li></ul><p>Next, we recommend studying the <strong><a href="./../../platforms/">Platforms and Integration</a></strong> chapter to learn how to run the pipeline on different AI assistants.</p>',23)])])}const g=t(o,[["render",r]]);export{u as __pageData,g as default};
